mapper.update:
UPDATE users 
SET username = #{username}, 
    email = #{email}, 
    is_active = #{is_active}, 
    role = #{role}
WHERE id = #{id}

mapper.select:
SELECT DISTINCT u.* FROM users u INNER JOIN user_roles ur ON u.id = ur.user_id INNER JOIN roles r ON ur.role_id = r.id WHERE r.role_key IN
#{roleKey}
AND u.is_active = true ORDER BY u.username
